import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-eventos',
  templateUrl: './eventos.component.html',
  styleUrls: ['./eventos.component.scss']
})

export class EventosComponent  implements OnInit {

  public eventos: any = [
  {
    Tema: 'Angular',
    Local: 'São Paulo'
  },
  {
    Tema: 'Angular e .Net',
    Local: 'São Paulo'
  },
  {
    Tema: '.Net 6 e suas novidades',
    Local: 'São Paulo'
  }
]

  constructor() {}

  ngOnInit(): void{

  }
}
<h1>Eventos do Components</h1>

<p><b>Tema:</b>{{eventos[0].Tema}}</p>
<p><b>Local</b>{{eventos[0].Local}}</p>

